class Solution {
    public List<Integer> findAllPeople(int n, int[][] meetings, int firstPerson) {
        boolean[] knows = new boolean[n];
        knows[0] = true;
        knows[firstPerson] = true;

        Arrays.sort(meetings, (a, b) -> Integer.compare(a[2], b[2]));

        int m = meetings.length;
        int i = 0;
        while (i < m) {
            int t = meetings[i][2];
            Map<Integer, List<Integer>> graph = new HashMap<>();
            Set<Integer> nodes = new HashSet<>();

            while (i < m && meetings[i][2] == t) {
                int x = meetings[i][0];
                int y = meetings[i][1];
                graph.computeIfAbsent(x, k -> new ArrayList<>()).add(y);
                graph.computeIfAbsent(y, k -> new ArrayList<>()).add(x);
                nodes.add(x);
                nodes.add(y);
                i++;
            }

            Queue<Integer> q = new LinkedList<>();
            for (int node : nodes) {
                if (knows[node]) {
                    q.offer(node);
                }
            }

            while (!q.isEmpty()) {
                int cur = q.poll();
                for (int neighbor : graph.getOrDefault(cur, Collections.emptyList())) {
                    if (!knows[neighbor]) {
                        knows[neighbor] = true;
                        q.offer(neighbor);
                    }
                }
            }
        }

        List<Integer> res = new ArrayList<>();
        for (int j = 0; j < n; j++) {
            if (knows[j]) {
                res.add(j);
            }
        }
        return res;
    }
}
